def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    index = 0
    t = int(data[index])
    index += 1
    results = []

    for _ in range(t):
        n = int(data[index])
        m = int(data[index + 1])
        index += 2

        grid = []
        for i in range(n):
            grid.append(data[index])
            index += 1

        # Initialize the minimum operations to a large number
        min_operations = float('inf')

        # Check all possible top-left corners of the portal
        for i in range(n - 4):
            for j in range(m - 3):
                # Calculate the number of operations needed to make a portal starting at (i, j)
                operations = 0

                # Top and bottom rows
                for x in range(j + 1, j + 3):
                    if grid[i][x] == '0':
                        operations += 1
                    if grid[i + 4][x] == '0':
                        operations += 1

                # Left and right columns
                for y in range(i + 1, i + 4):
                    if grid[y][j] == '0':
                        operations += 1
                    if grid[y][j + 3] == '0':
                        operations += 1

                # Inner empty area
                for y in range(i + 1, i + 4):
                    for x in range(j + 1, j + 3):
                        if grid[y][x] == '1':
                            operations += 1

                # Update the minimum operations
                min_operations = min(min_operations, operations)

        results.append(min_operations)

    for result in results:
        print(result)

