def is_composite(x):
    if x < 4:
        return False
    for i in range(2, int(x**0.5) + 1):
        if x % i == 0:
            return True
    return False

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    index = 0
    t = int(data[index])
    index += 1
    results = []

    for _ in range(t):
        n = int(data[index])
        index += 1
        a = list(map(int, data[index:index + n]))
        index += n

        total_sum = sum(a)

        if is_composite(total_sum):
            results.append((n, list(range(1, n + 1))))
        else:
            # Find one element to remove to make the sum composite
            for i in range(n):
                if is_composite(total_sum - a[i]):
                    indices = [j + 1 for j in range(n) if j != i]
                    results.append((n - 1, indices))
                    break

    for result in results:
        print(result[0])
        print(" ".join(map(str, result[1])))

