def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    t = int(data[0])
    index = 1
    results = []

    for _ in range(t):
        s = data[index]
        index += 1

        # Count AB and BA
        ab_count = 0
        ba_count = 0

        for i in range(len(s) - 1):
            if s[i] == 'a' and s[i + 1] == 'b':
                ab_count += 1
            elif s[i] == 'b' and s[i + 1] == 'a':
                ba_count += 1

        # If counts are already equal, no change needed
        if ab_count == ba_count:
            results.append(s)
        else:
            # We need to make a change to balance AB and BA
            # Change the first character to balance the counts
            if ab_count > ba_count:
                # More ABs, reduce by changing the first 'a' to 'b'
                if s[0] == 'a':
                    results.append('b' + s[1:])
                else:
                    results.append(s[0] + 'a' + s[2:])
            else:
                # More BAs, reduce by changing the first 'b' to 'a'
                if s[0] == 'b':
                    results.append('a' + s[1:])
                else:
                    results.append(s[0] + 'b' + s[2:])

    for result in results:
        print(result)

